changeSet.sql:
DO $$
DECLARE
    rec   RECORD;
    max_id BIGINT;
    sql_stmt TEXT;
BEGIN
    FOR rec IN
        SELECT s.sequence_name,
               replace(s.sequence_name, '_seq', '') AS table_name
        FROM information_schema.sequences s
        WHERE s.sequence_schema = 'clinlims'
          AND s.sequence_name LIKE '%\_seq' ESCAPE '\'
    LOOP
        -- Skip sequences whose target table doesn't exist or has no `id` column
        IF NOT EXISTS (
            SELECT 1 FROM information_schema.columns c
            WHERE c.table_schema = 'clinlims'
              AND c.table_name = rec.table_name
              AND c.column_name = 'id'
        ) THEN
            CONTINUE;
        END IF;

        sql_stmt := format(
            'SELECT COALESCE(MAX(id::bigint), 0) FROM clinlims.%I',
            rec.table_name
        );
        EXECUTE sql_stmt INTO max_id;

        -- setval to MAX(id)+1; if table empty, set to 1 with is_called=false so next nextval() = 1
        IF max_id = 0 THEN
            PERFORM setval(format('clinlims.%I', rec.sequence_name), 1, false);
        ELSE
            PERFORM setval(format('clinlims.%I', rec.sequence_name), max_id + 1, false);
        END IF;
    END LOOP;
END $$;
